import{_ as e,o as a,c as i,a2 as l}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"支票入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/hk-methods/cheque.md","filePath":"zh-CN/deposit/hk-methods/cheque.md"}'),o={name:"deposit/hk-methods/cheque.md"};function r(d,t,h,s,n,u){return a(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="支票入金" tabindex="-1">支票入金 <a class="header-anchor" href="#支票入金" aria-label="Permalink to &quot;支票入金&quot;">​</a></h1><p>通过香港银行支票将资金转账至长桥收款账户，转账完成后需上传支票及汇款凭证。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）、美元（USD）</td></tr><tr><td>预计到账时间</td><td>约 2 个工作日</td></tr><tr><td>手续费</td><td>长桥免费，具体费用以银行实际收取为准</td></tr></tbody></table><h2 id="收款银行信息" tabindex="-1">收款银行信息 <a class="header-anchor" href="#收款银行信息" aria-label="Permalink to &quot;收款银行信息&quot;">​</a></h2><ul><li>收款人名称：Long Bridge HK Limited</li><li>港元收款账号：01287520564946</li><li>美元收款账号：01287520564962</li><li>收款银行：中国银行（香港）有限公司（银行编号：012）</li></ul><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>填写支票：正面收款人填写 <strong>Long Bridge HK Limited</strong>；反面填写<strong>长桥综合账户 + 你的账户号码</strong>（如「长桥综合账户（H10057829）」），并拍摄正反面照片</li><li>将支票递交至银行柜台或存支票机，保留转账凭证截图</li><li>打开长桥 App，进入<strong>资产 → 存入资金 → 支票转账</strong>，上传支票正面、反面截图和转账凭证</li></ol><blockquote><p>完成后请立即上传所有凭证，否则影响入金进度。</p></blockquote><h2 id="支票类型与限制" tabindex="-1">支票类型与限制 <a class="header-anchor" href="#支票类型与限制" aria-label="Permalink to &quot;支票类型与限制&quot;">​</a></h2><ul><li>仅支持香港银行支票，不支持香港银行本票</li><li>不建议支票转至工银亚洲收款账户（核对资料需额外时间）</li><li>转账银行账户名必须与证券账户名同名，不可使用他人账户</li><li>香港公众假期不处理汇款业务，请预留时间</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/methods-overview">入金方式总览</a> — 对比所有入金方式的预计到账时间与手续费</li><li><a href="/wiki/troubleshooting/deposit-not-received">入金未到账排查</a> — 超出预期时间未到账时的排查步骤</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit">入金</a></li><li><a href="/wiki/deposit/methods-overview">入金方式</a></li></ul>',15)])])}const m=e(o,[["render",r]]);export{p as __pageData,m as default};
